def gen(rng, size):
    n = max(1, size)
    names = []
    bases = [f"b{i}" for i in range(200)]
    for _ in range(n):
        base = rng.choice(bases)
        if rng.random() < 0.3:
            names.append(f"{base}({rng.randint(1, 5)})")
        else:
            names.append(base)
    return [names]

