class Solution:
    def getFolderNames(self, names):
        used = set()
        res = []
        for name in names:
            if name not in used:
                res.append(name)
                used.add(name)
            else:
                k = 1
                while f'{name}({k})' in used:
                    k += 1
                new_name = f'{name}({k})'
                res.append(new_name)
                used.add(new_name)
        return res

