class Solution:
    def getFolderNames(self, names):
        used = {}
        res = []
        for name in names:
            if name not in used:
                res.append(name)
                used[name] = 1
            else:
                k = used[name]
                new_name = f'{name}({k})'
                while new_name in used:
                    k += 1
                    new_name = f'{name}({k})'
                res.append(new_name)
                used[new_name] = 1
                used[name] = k + 1
        return res

