var getFolderNames = function(names) {
    const used = new Map();
    const res = [];
    for (const name of names) {
        if (!used.has(name)) {
            res.push(name);
            used.set(name, 1);
        } else {
            let k = used.get(name);
            let newName = `${name}(${k})`;
            while (used.has(newName)) {
                k += 1;
                newName = `${name}(${k})`;
            }
            res.push(newName);
            used.set(newName, 1);
            used.set(name, k + 1);
        }
    }
    return res;
};
